// Parse Octagon Agent response and merge all quote fields back with the current ticker row.
// Works with Octagon outputs returned as JSON, markdown tables, plain text, or nested OpenAI-style payloads.

function getCurrentTickerRow() {
  try {
    return $('Loop Over Tickers').item.json || {};
  } catch (e) {}

  try {
    return $('Loop Over Tickers').first().json || {};
  } catch (e) {}

  return {};
}

function stringifySafe(value) {
  if (typeof value === 'string') return value;
  if (value == null) return '';
  try {
    return JSON.stringify(value, null, 2);
  } catch (e) {
    return String(value);
  }
}

function unwrapText(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;

  // Common Octagon / agent fields
  if (typeof value.analysis === 'string') return value.analysis;
  if (typeof value.output_text === 'string') return value.output_text;
  if (typeof value.text === 'string') return value.text;
  if (typeof value.response === 'string') return value.response;
  if (typeof value.result === 'string') return value.result;
  if (typeof value.answer === 'string') return value.answer;

  // OpenAI-style message/content arrays
  if (value.message?.content) {
    if (typeof value.message.content === 'string') return value.message.content;
    if (Array.isArray(value.message.content)) {
      return value.message.content
        .map(c => c?.text || c?.content || c?.value || '')
        .join('\n')
        .trim();
    }
  }

  if (Array.isArray(value.content)) {
    return value.content
      .map(c => c?.text || c?.content || c?.value || '')
      .join('\n')
      .trim();
  }

  // Some Octagon node responses place the generated prompt/result inside query as JSON string
  if (value.query) {
    try {
      const q = typeof value.query === 'string' ? JSON.parse(value.query) : value.query;
      const text = q?.output?.[0]?.content?.[0]?.text;
      if (text) return text;
    } catch (e) {
      if (typeof value.query === 'string') return value.query;
    }
  }

  return stringifySafe(value);
}

function stripCodeFences(text) {
  return String(text || '')
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```javascript\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseJsonObjectFromText(text) {
  const cleaned = stripCodeFences(text);
  if (!cleaned) return {};

  // Try the whole text first
  try {
    const parsed = JSON.parse(cleaned);
    if (parsed && typeof parsed === 'object') return parsed;
  } catch (e) {}

  // Try each balanced-ish object candidate from first { to each later }
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    const candidate = cleaned.slice(firstBrace, lastBrace + 1);
    try {
      const parsed = JSON.parse(candidate);
      if (parsed && typeof parsed === 'object') return parsed;
    } catch (e) {}
  }

  return {};
}

function flattenObject(obj, prefix = '', out = {}) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return out;

  for (const [key, value] of Object.entries(obj)) {
    const cleanKey = String(key).trim();
    const path = prefix ? `${prefix}.${cleanKey}` : cleanKey;

    if (value && typeof value === 'object' && !Array.isArray(value)) {
      flattenObject(value, path, out);
    } else {
      out[path] = value;
      out[cleanKey] = value; // keep simple alias too
    }
  }

  return out;
}

function normalizeKey(key) {
  return String(key || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function getFirst(obj, keys, fallback = '') {
  if (!obj || typeof obj !== 'object') return fallback;

  const flat = flattenObject(obj);
  const normalized = {};

  for (const [key, value] of Object.entries(flat)) {
    normalized[normalizeKey(key)] = value;
  }

  for (const key of keys) {
    const direct = flat[key];
    if (direct !== undefined && direct !== null && direct !== '') return direct;

    const norm = normalized[normalizeKey(key)];
    if (norm !== undefined && norm !== null && norm !== '') return norm;
  }

  return fallback;
}

function extractMetric(text, metric) {
  const escapedMetric = metric.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  // Markdown table row: | Metric | Value |
  const tableRegex = new RegExp(`\\|\\s*${escapedMetric}\\s*\\|\\s*([^|]+)\\|`, 'i');
  const tableMatch = String(text || '').match(tableRegex);
  if (tableMatch) return tableMatch[1].trim();

  // Label/value forms: Metric: value OR Metric - value
  const labelRegex = new RegExp(`${escapedMetric}\\s*[:\\-–—]\\s*([^\\n|]+)`, 'i');
  const labelMatch = String(text || '').match(labelRegex);
  if (labelMatch) return labelMatch[1].trim();

  return '';
}

function firstMetric(text, labels) {
  for (const label of labels) {
    const value = extractMetric(text, label);
    if (value) return value;
  }
  return '';
}

const original = getCurrentTickerRow();
const octagonRaw = $input.first().json;
const raw = stringifySafe(octagonRaw);
const analysis = unwrapText(octagonRaw) || raw;
const parsed = parseJsonObjectFromText(analysis);

const ticker =
  original.Ticker ||
  original.TICKER ||
  getFirst(parsed, ['ticker', 'symbol', 'quote.ticker', 'quote.symbol']) ||
  firstMetric(analysis, ['Ticker', 'Symbol']);

const currentPrice =
  getFirst(parsed, [
    'current_price', 'currentPrice', 'price', 'last_price', 'lastPrice', 'last',
    'Last Price', 'Current Price', 'quote.current_price', 'quote.price', 'quote.last_price'
  ]) ||
  firstMetric(analysis, ['Last Price', 'Current Price', 'Price', 'Current']);

const change =
  getFirst(parsed, ['change', 'price_change', 'priceChange', 'regularMarketChange', 'quote.change']) ||
  firstMetric(analysis, ['Change', 'Price Change']);

const volume =
  getFirst(parsed, ['volume', 'regularMarketVolume', 'quote.volume']) ||
  firstMetric(analysis, ['Volume']);

const dayRange =
  getFirst(parsed, ['day_range', 'dayRange', 'regularMarketDayRange', 'quote.day_range']) ||
  firstMetric(analysis, ['Day Range', 'Daily Range']);

const week52Range =
  getFirst(parsed, [
    '52_week_range', '52WeekRange', 'fifty_two_week_range', 'fiftyTwoWeekRange',
    'week_52_range', 'quote.52_week_range'
  ]) ||
  firstMetric(analysis, ['52W Range', '52-Week Range', '52 Week Range', '52-week range']);

const marketCap =
  getFirst(parsed, ['market_cap', 'marketCap', 'regularMarketMarketCap', 'quote.market_cap']) ||
  firstMetric(analysis, ['Market Cap', 'Market Capitalization']);

const exchange =
  getFirst(parsed, ['exchange', 'exchangeName', 'fullExchangeName', 'quote.exchange']) ||
  firstMetric(analysis, ['Exchange']);

const previousClose =
  getFirst(parsed, ['previous_close', 'previousClose', 'regularMarketPreviousClose', 'quote.previous_close']) ||
  firstMetric(analysis, ['Previous Close', 'Prev Close']);

const ma50 =
  getFirst(parsed, [
    '50_day_average', 'fifty_day_average', 'fiftyDayAverage', '50_day_ma',
    'fifty_day_ma', '50DayAverage', 'quote.50_day_average'
  ]) ||
  firstMetric(analysis, ['50-Day Average', '50-Day MA', '50-Day Moving Average', '50 Day Average']);

const ma200 =
  getFirst(parsed, [
    '200_day_average', 'two_hundred_day_average', 'twoHundredDayAverage', '200_day_ma',
    '200DayAverage', 'quote.200_day_average'
  ]) ||
  firstMetric(analysis, ['200-Day Average', '200-Day MA', '200-Day Moving Average', '200 Day Average']);

const date =
  getFirst(parsed, ['quote_time', 'quoteTime', 'as_of', 'asOf', 'timestamp', 'date', 'time', 'metadata.timestamp']) ||
  firstMetric(analysis, ['As Of (UTC)', 'As Of', 'Quote Time', 'Timestamp', 'Date']) ||
  octagonRaw.metadata?.timestamp ||
  new Date().toISOString();

const sourceStatus =
  getFirst(parsed, ['source_status', 'sourceStatus', 'source', 'status', 'provider']) ||
  firstMetric(analysis, ['Source', 'Status', 'Source/Status']);

return [{
  json: {
    row_number: original.row_number,
    Ticker: ticker,
    'Current Price': currentPrice,
    Change: change,
    Volume: volume,
    'Day Range': dayRange,
    '52-Week Range': week52Range,
    'Market Cap': marketCap,
    Exchange: exchange,
    'Previous Close': previousClose,
    '50-Day Average': ma50,
    '200-Day Average': ma200,
    Date: date,
    'Octagon Response': analysis,
    'Octagon Source/Status': sourceStatus,
    _parsedQuoteJson: parsed
  }
}];
